     1→import { listen } from "@tauri-apps/api/event";
     2→import { useEffect, useRef, useState } from "react";
     3→import { CommitDialog } from "./components/CommitDialog";
     4→import { Editor } from "./components/Editor";
     5→import { EmptyState } from "./components/EmptyState";
     6→import { ErrorBoundary } from "./components/ErrorBoundary";
     7→import { FileSwitcher } from "./components/FileSwitcher";
     8→import { NewFileDialog } from "./components/NewFileDialog";
     9→import { PropertiesPanel } from "./components/PropertiesPanel";
    10→import { SearchPanel } from "./components/SearchPanel";
    11→import { Sidebar } from "./components/Sidebar";
    12→import { StatusBar } from "./components/StatusBar";
    13→import { WorkspaceSwitcher } from "./components/WorkspaceSwitcher";
    14→import { resolveImageSrc } from "./lib/imageUtils";
    15→import { useContentTypes } from "./lib/useContentTypes";
    16→import { useEditorPreferences } from "./lib/useEditorPreferences";
    17→import { useFileEditor } from "./lib/useFileEditor";
    18→import { useGit } from "./lib/useGit";
    19→import { useRecentFiles } from "./lib/useRecentFiles";
    20→import { useRecentWorkspaces } from "./lib/useRecentWorkspaces";
    21→import { useTheme } from "./lib/useTheme";
    22→import { useToast } from "./lib/useToast";
    23→import { useWordCountGoal } from "./lib/useWordCountGoal";
    24→import { useWorkspace } from "./lib/useWorkspace";
    25→import "./styles/global.css";
    26→import "./App.css";
    27→
    28→type ModalState = { type: "new-file"; dirPath: string; contentType?: string } | null;
    29→type CommitDialogState = { message: string; branch: string } | null;
    30→
    31→const SIDEBAR_VISIBLE_KEY = "ovid:sidebarVisible";
    32→const AUTO_REOPEN_KEY = "ovid:skipAutoReopen";
    33→
    34→function App() {
    35→  const { resolvedTheme, setPreference } = useTheme();
    36→  const [sidebarVisible, setSidebarVisible] = useState(
    37→    () => localStorage.getItem(SIDEBAR_VISIBLE_KEY) !== "false"
    38→  );
    39→  const [propertiesOpen, setPropertiesOpen] = useState(true);
    40→  const [zenMode, setZenMode] = useState(false);
    41→  const [typewriterMode, setTypewriterMode] = useState(false);
    42→  const [sessionBaseline, setSessionBaseline] = useState<number | null>(null);
    43→  const [baselineCaptured, setBaselineCaptured] = useState(false);
    44→  const [modal, setModal] = useState<ModalState>(null);
    45→  const [switcherOpen, setSwitcherOpen] = useState(false);
    46→  const [workspaceSwitcherOpen, setWorkspaceSwitcherOpen] = useState(false);
    47→  const [searchOpen, setSearchOpen] = useState(false);
    48→  const [commitDialog, setCommitDialog] = useState<CommitDialogState>(null);
    49→  const [coverImageVisible, setCoverImageVisible] = useState(false);
    50→
    51→  const { toasts, showToast } = useToast();
    52→  const { prefs, updatePrefs } = useEditorPreferences();
    53→  const { goal: wordCountGoal, setGoal: setWordCountGoal } = useWordCountGoal();
    54→
    55→  const {
    56→    selectedFile,
    57→    setSelectedFile,
    58→    fileContent,
    59→    wordCount,
    60→    setWordCount,
    61→    parsedFrontmatter,
    62→    saveStatus,
    63→    selectedPathRef,
    64→    flushPendingSave,
    65→    resetFileState,
    66→    handleCloseFile,
    67→    handleSelectFile,
    68→    handleEditorChange,
    69→    handleFieldChange,
    70→  } = useFileEditor({ showToast });
    71→
    72→  const {
    73→    tree,
    74→    workspaceName,
    75→    workspaceRoot,
    76→    workspaceRootPath,
    77→    isAmytisWorkspace,
    78→    assetRoot,
    79→    cdnBase,
    80→    renamingPath,
    81→    setRenamingPath,
    82→    handleOpenWorkspace,
    83→    openWorkspaceAtPath,
    84→    handleNewFile,
    85→    handleRename,
    86→    handleDelete,
    87→  } = useWorkspace({
    88→    showToast,
    89→    flushPendingSave,
    90→    handleCloseFile,
    91→    handleSelectFile,
    92→    selectedFile,
    93→    selectedPathRef,
    94→    setSelectedFile,
    95→    resetFileState,
    96→  });
    97→
    98→  const { recentFiles, pushRecent, resetRecent } = useRecentFiles(workspaceRoot);
    99→  const { recentWorkspaces, pushRecentWorkspace } = useRecentWorkspaces();
   100→  const { gitStatusMap, isGitRepo, refreshGitStatus, handleCommit, getBranch } =
   101→    useGit(workspaceRoot);
   102→  const contentTypes = useContentTypes(workspaceRoot, isAmytisWorkspace);
   103→
   104→  // Sync recent files list when workspace changes
   105→  useEffect(() => {
   106→    if (workspaceRoot) resetRecent(workspaceRoot);
   107→  }, [workspaceRoot, resetRecent]);
   108→
   109→  // Track recently opened workspaces
   110→  useEffect(() => {
   111→    if (workspaceRootPath && workspaceName) {
   112→      pushRecentWorkspace(workspaceRootPath, workspaceName);
   113→    }
   114→  }, [workspaceRootPath, workspaceName, pushRecentWorkspace]);
   115→
   116→  // Auto-reopen last workspace on launch (once)
   117→  const autoReopenAttempted = useRef(false);
   118→  useEffect(() => {
   119→    if (
   120→      autoReopenAttempted.current ||
   121→      workspaceRootPath !== null ||
   122→      recentWorkspaces.length === 0 ||
   123→      localStorage.getItem(AUTO_REOPEN_KEY) === "true"
   124→    )
   125→      return;
   126→    autoReopenAttempted.current = true;
   127→    void openWorkspaceAtPath(recentWorkspaces[0].rootPath);
   128→  }, [recentWorkspaces, openWorkspaceAtPath, workspaceRootPath]);
   129→
   130→  // Reset per-file UI state when switching files (selectedFile is the trigger, not used in body)
   131→  // biome-ignore lint/correctness/useExhaustiveDependencies: selectedFile is the intended trigger
   132→  useEffect(() => {
   133→    setSessionBaseline(null);
   134→    setBaselineCaptured(false);
   135→    setCoverImageVisible(false);
   136→  }, [selectedFile]);
   137→
   138→  // Capture baseline on first word-count event for the new file (including empty files)
   139→  useEffect(() => {
   140→    if (!baselineCaptured) {
   141→      setSessionBaseline(wordCount);
   142→      setBaselineCaptured(true);
   143→    }
   144→  }, [wordCount, baselineCaptured]);
   145→
   146→  // Global keyboard shortcuts
   147→  useEffect(() => {
   148→    function onKeyDown(e: KeyboardEvent) {
   149→      // Escape exits zen mode (before other guards)
   150→      if (
   151→        e.key === "Escape" &&
   152→        zenMode &&
   153→        !modal &&
   154→        !commitDialog &&
   155→        !switcherOpen &&
   156→        !workspaceSwitcherOpen
   157→      ) {
   158→        setZenMode(false);
   159→        return;
   160→      }
   161→      if (!e.metaKey && !e.ctrlKey) return;
   162→      // Ctrl+Cmd+Z — zen mode (macOS); avoids conflict with Redo (Cmd+Shift+Z)
   163→      if (e.metaKey && e.ctrlKey && e.key === "z") {
   164→        e.preventDefault();
   165→        setZenMode((v) => !v);
   166→        return;
   167→      }
   168→      // Mode toggles work even when editor has focus
   169→      if (e.shiftKey && e.key === "P") {
   170→        e.preventDefault();
   171→        setPropertiesOpen((v) => !v);
   172→        return;
   173→      }
   174→      const target = e.target as HTMLElement;
   175→      if (
   176→        target instanceof HTMLInputElement ||
   177→        target instanceof HTMLTextAreaElement ||
   178→        target.isContentEditable
   179→      )
   180→        return;
   181→      switch (e.key) {
   182→        case "\\":
   183→          e.preventDefault();
   184→          setSidebarVisible((v) => {
   185→            const next = !v;
   186→            localStorage.setItem(SIDEBAR_VISIBLE_KEY, String(next));
   187→            return next;
   188→          });
   189→          break;
   190→        case "o":
   191→          e.preventDefault();
   192→          if (e.shiftKey) {
   193→            setWorkspaceSwitcherOpen(true);
   194→          } else {
   195→            void handleOpenWorkspace();
   196→          }
   197→          break;
   198→        case "F":
   199→          if (e.shiftKey) {
   200→            e.preventDefault();
   201→            if (workspaceRoot) setSearchOpen((v) => !v);
   202→          }
   203→          break;
   204→        case "G":
   205→          if (e.shiftKey && isGitRepo) {
   206→            e.preventDefault();
   207→            void getBranch()
   208→              .then((branch) => {
   209→                const title = parsedFrontmatter.title ?? selectedFile?.name ?? "";
   210→                setCommitDialog({ message: `Update: ${title}`, branch });
   211→              })
   212→              .catch(() => showToast("Failed to get git branch"));
   213→          }
   214→          break;
   215→        case "p":
   216→          e.preventDefault();
   217→          if (tree.length > 0) setSwitcherOpen(true);
   218→          break;
   219→        case "n":
   220→          e.preventDefault();
   221→          if (workspaceRoot)
   222→            setModal({ type: "new-file", dirPath: workspaceRoot, contentType: "post" });
   223→          break;
   224→        case "s":
   225→          e.preventDefault();
   226→          void flushPendingSave();
   227→          break;
   228→        case "w":
   229→          e.preventDefault();
   230→          void handleCloseFile();
   231→          break;
   232→      }
   233→    }
   234→    window.addEventListener("keydown", onKeyDown);
   235→    return () => window.removeEventListener("keydown", onKeyDown);
   236→  }, [
   237→    flushPendingSave,
   238→    handleCloseFile,
   239→    handleOpenWorkspace,
   240→    workspaceRoot,
   241→    tree,
   242→    isGitRepo,
   243→    getBranch,
   244→    parsedFrontmatter,
   245→    selectedFile,
   246→    showToast,
   247→    zenMode,
   248→    modal,
   249→    commitDialog,
   250→    switcherOpen,
   251→    workspaceSwitcherOpen,
   252→  ]);
   253→
   254→  // Refresh git status after each save completes
   255→  useEffect(() => {
   256→    if (saveStatus === "saved" && isGitRepo) void refreshGitStatus();
   257→  }, [saveStatus, isGitRepo, refreshGitStatus]);
   258→
   259→  // Forward native menu events to the same handlers as keyboard shortcuts
   260→  useEffect(() => {
   261→    let mounted = true;
   262→    let unlisten: (() => void) | undefined;
   263→    listen<string>("menu-action", (event) => {
   264→      const hasBlockingOverlay =
   265→        modal !== null || commitDialog !== null || switcherOpen || workspaceSwitcherOpen;
   266→      switch (event.payload) {
   267→        case "new-post":
   268→        case "new-flow":
   269→        case "new-note":
   270→        case "new-series":
   271→        case "new-book":
   272→        case "new-page":
   273→          if (!hasBlockingOverlay && workspaceRoot)
   274→            setModal({
   275→              type: "new-file",
   276→              dirPath: workspaceRoot,
   277→              contentType: event.payload.replace("new-", ""),
   278→            });
   279→          break;
   280→        case "open-workspace":
   281→          void handleOpenWorkspace();
   282→          break;
   283→        case "switch-workspace":
   284→          if (!hasBlockingOverlay) setWorkspaceSwitcherOpen(true);
   285→          break;
   286→        case "save":
   287→          void flushPendingSave();
   288→          break;
   289→        case "close-file":
   290→          void handleCloseFile();
   291→          break;
   292→        case "toggle-sidebar":
   293→          setSidebarVisible((v) => {
   294→            const next = !v;
   295→            localStorage.setItem(SIDEBAR_VISIBLE_KEY, String(next));
   296→            return next;
   297→          });
   298→          break;
   299→        case "toggle-properties":
   300→          setPropertiesOpen((v) => !v);
   301→          break;
   302→        case "toggle-search":
   303→          if (workspaceRoot) setSearchOpen((v) => !v);
   304→          break;
   305→        case "zen-mode":
   306→          setZenMode((v) => !v);
   307→          break;
   308→        case "typewriter-mode":
   309→          setTypewriterMode((v) => !v);
   310→          break;
   311→        case "file-switcher":
   312→          if (!hasBlockingOverlay && tree.length > 0) setSwitcherOpen(true);
   313→          break;
   314→        case "toggle-spell-check":
   315→          updatePrefs({ spellCheck: !prefs.spellCheck });
   316→          break;
   317→        case "commit-push":
   318→          if (!hasBlockingOverlay && isGitRepo) {
   319→            void getBranch()
   320→              .then((branch) => {
   321→                const title = parsedFrontmatter.title ?? selectedFile?.name ?? "";
   322→                setCommitDialog({ message: `Update: ${title}`, branch });
   323→              })
   324→              .catch(() => showToast("Failed to get git branch"));
   325→          }
   326→          break;
   327→      }
   328→    }).then((fn) => {
   329→      if (mounted) {
   330→        unlisten = fn;
   331→      } else {
   332→        fn();
   333→      }
   334→    });
   335→    return () => {
   336→      mounted = false;
   337→      unlisten?.();
   338→    };
   339→  }, [
   340→    modal,
   341→    commitDialog,
   342→    switcherOpen,
   343→    workspaceSwitcherOpen,
   344→    workspaceRoot,
   345→    tree,
   346→    isGitRepo,
   347→    getBranch,
   348→    parsedFrontmatter,
   349→    selectedFile,
   350→    showToast,
   351→    flushPendingSave,
   352→    handleCloseFile,
   353→    handleOpenWorkspace,
   354→    prefs,
   355→    updatePrefs,
   356→  ]);
   357→
   358→  const hasFrontmatter = Object.keys(parsedFrontmatter).length > 0;
   359→  const coverImagePath =
   360→    parsedFrontmatter.coverImage !== undefined ? String(parsedFrontmatter.coverImage) : undefined;
   361→
   362→  async function handlePublishAwareFieldChange(key: string, value: unknown) {
   363→    await handleFieldChange(key, value as Parameters<typeof handleFieldChange>[1]);
   364→    if (key === "draft" && value === false && isGitRepo) {
   365→      try {
   366→        const branch = await getBranch();
   367→        const title = parsedFrontmatter.title ?? selectedFile?.name ?? "";
   368→        setCommitDialog({ message: `Publish: ${title}`, branch });
   369→      } catch {
   370→        // git unavailable — ignore
   371→      }
   372→    }
   373→  }
   374→
   375→  function handleOpenByPath(path: string) {
   376→    const node = tree
   377→      .flatMap(function flatten(n): typeof tree {
   378→        return n.isDirectory ? (n.children ?? []).flatMap(flatten) : [n];
   379→      })
   380→      .find((n) => n.path === path);
   381→    if (node) {
   382→      void handleSelectFile(node);
   383→      pushRecent(node);
   384→      setSearchOpen(false);
   385→    }
   386→  }
   387→
   388→  const sessionWordsAdded = sessionBaseline !== null ? Math.max(0, wordCount - sessionBaseline) : 0;
   389→
   390→  return (
   391→    <div className="app" data-zen={zenMode ? "true" : undefined}>
   392→      <div className="app-body">
   393→        {searchOpen ? (
   394→          <SearchPanel onOpenFile={handleOpenByPath} onClose={() => setSearchOpen(false)} />
   395→        ) : (
   396→          <Sidebar
   397→            tree={tree}
   398→            selectedPath={selectedFile?.path ?? null}
   399→            renamingPath={renamingPath}
   400→            visible={sidebarVisible}
   401→            workspaceName={workspaceName}
   402→            gitStatusMap={gitStatusMap}
   403→            onSelect={(node) => {
   404→              void handleSelectFile(node);
   405→              if (!node.isDirectory) pushRecent(node);
   406→            }}
   407→            onOpenWorkspace={handleOpenWorkspace}
   408→            onOpenSwitcher={() => setWorkspaceSwitcherOpen(true)}
   409→            onNewFile={(dirPath) => setModal({ type: "new-file", dirPath })}
   410→            onRename={handleRename}
   411→            onDelete={handleDelete}
   412→            onStartRename={setRenamingPath}
   413→            onCancelRename={() => setRenamingPath(null)}
   414→          />
   415→        )}
   416→        <div className="editor-column">
   417→          {selectedFile && coverImageVisible && coverImagePath && (
   418→            <div className="cover-image-banner">
   419→              <img
   420→                src={resolveImageSrc(coverImagePath, selectedFile.path, assetRoot, cdnBase)}
   421→                alt={parsedFrontmatter.title ? String(parsedFrontmatter.title) : ""}
   422→              />
   423→            </div>
   424→          )}
   425→          {selectedFile ? (
   426→            <ErrorBoundary key={selectedFile.path}>
   427→              <Editor
   428→                key={selectedFile.path}
   429→                content={fileContent}
   430→                filePath={selectedFile.path}
   431→                assetRoot={assetRoot}
   432→                cdnBase={cdnBase}
   433→                typewriterMode={typewriterMode}
   434→                spellCheck={prefs.spellCheck}
   435→                onWordCount={setWordCount}
   436→                onChange={handleEditorChange}
   437→              />
   438→            </ErrorBoundary>
   439→          ) : (
   440→            <EmptyState
   441→              workspaceOpen={workspaceRoot !== null}
   442→              recentFiles={recentFiles}
   443→              onOpenWorkspace={handleOpenWorkspace}
   444→              onOpenRecent={handleOpenByPath}
   445→            />
   446→          )}
   447→        </div>
   448→        {selectedFile && hasFrontmatter && (
   449→          <PropertiesPanel
   450→            frontmatter={parsedFrontmatter}
   451→            visible={propertiesOpen}
   452→            slug={selectedFile.name.replace(/\.mdx?$/, "")}
   453→            coverImageVisible={coverImageVisible}
   454→            onFieldChange={handlePublishAwareFieldChange}
   455→            onToggleCoverImage={() => setCoverImageVisible((v) => !v)}
   456→          />
   457→        )}
   458→      </div>
   459→      <StatusBar
   460→        fileName={selectedFile?.name ?? null}
   461→        wordCount={wordCount}
   462→        resolvedTheme={resolvedTheme}
   463→        saveStatus={saveStatus}
   464→        zenMode={zenMode}
   465→        typewriterMode={typewriterMode}
   466→        sessionWordsAdded={sessionWordsAdded}
   467→        wordCountGoal={wordCountGoal}
   468→        fontFamily={prefs.fontFamily}
   469→        fontSize={prefs.fontSize}
   470→        spellCheck={prefs.spellCheck}
   471→        onToggleTheme={() => setPreference(resolvedTheme === "dark" ? "light" : "dark")}
   472→        onToggleZen={() => setZenMode((v) => !v)}
   473→        onToggleTypewriter={() => setTypewriterMode((v) => !v)}
   474→        onSetFontFamily={(f) => updatePrefs({ fontFamily: f })}
   475→        onSetFontSize={(s) => updatePrefs({ fontSize: s })}
   476→        onToggleSpellCheck={() => updatePrefs({ spellCheck: !prefs.spellCheck })}
   477→        onSetWordCountGoal={setWordCountGoal}
   478→      />
   479→      {toasts.length > 0 && (
   480→        <div className="toast-container">
   481→          {toasts.map((t) => (
   482→            <div key={t.id} className="toast">
   483→              {t.message}
   484→            </div>
   485→          ))}
   486→        </div>
   487→      )}
   488→      {workspaceSwitcherOpen && (
   489→        <WorkspaceSwitcher
   490→          recentWorkspaces={recentWorkspaces}
   491→          currentRootPath={workspaceRootPath}
   492→          onSelect={(rootPath) => void openWorkspaceAtPath(rootPath)}
   493→          onOpenOther={handleOpenWorkspace}
   494→          onClose={() => setWorkspaceSwitcherOpen(false)}
   495→        />
   496→      )}
   497→      {switcherOpen && (
   498→        <FileSwitcher
   499→          tree={tree}
   500→          recentFiles={recentFiles}
   501→          onSelect={(node) => {
   502→            void handleSelectFile(node);
   503→            pushRecent(node);
   504→            setSwitcherOpen(false);
   505→          }}
   506→          onClose={() => setSwitcherOpen(false)}
   507→        />
   508→      )}
   509→      {modal?.type === "new-file" && (
   510→        <NewFileDialog
   511→          contentTypes={contentTypes}
   512→          preselectedType={modal.contentType}
   513→          onConfirm={(name, contentType) => {
   514→            void handleNewFile(modal.dirPath, name, contentType);
   515→            setModal(null);
   516→          }}
   517→          onCancel={() => setModal(null)}
   518→        />
   519→      )}
   520→      {commitDialog && (
   521→        <CommitDialog
   522→          defaultMessage={commitDialog.message}
   523→          branch={commitDialog.branch}
   524→          onCommit={(message, push) => {
   525→            void flushPendingSave()
   526→              .then(() => handleCommit(message, push))
   527→              .then(() => setCommitDialog(null))
   528→              .catch((err) => showToast(`Commit failed: ${err}`));
   529→          }}
   530→          onCancel={() => setCommitDialog(null)}
   531→        />
   532→      )}
   533→    </div>
   534→  );
   535→}
   536→
   537→export default App;
   538→

