     1→import { Menu, MenuItem, PredefinedMenuItem } from "@tauri-apps/api/menu";
     2→import { Folder, FolderOpen } from "lucide-react";
     3→import { Fragment, useEffect, useRef, useState } from "react";
     4→import { filterTree, needsPageDivider, rollupGitStatus, sortNodes } from "../lib/sidebarUtils";
     5→import type { FileNode, GitStatus } from "../lib/types";
     6→import { ContentTypeIcon } from "./ContentTypeIcon";
     7→import "./Sidebar.css";
     8→import { Input } from "./ui/input";
     9→
    10→interface SidebarProps {
    11→  tree: FileNode[];
    12→  selectedPath: string | null;
    13→  renamingPath: string | null;
    14→  visible: boolean;
    15→  workspaceName: string | null;
    16→  gitStatusMap: Map<string, GitStatus>;
    17→  onSelect: (node: FileNode) => void;
    18→  onOpenWorkspace: () => void;
    19→  onOpenSwitcher: () => void;
    20→  onNewFile: (dirPath: string) => void;
    21→  onRename: (node: FileNode, newName: string) => void;
    22→  onDelete: (node: FileNode) => void;
    23→  onStartRename: (path: string) => void;
    24→  onCancelRename: () => void;
    25→}
    26→
    27→interface FileItemProps {
    28→  node: FileNode;
    29→  depth: number;
    30→  selectedPath: string | null;
    31→  renamingPath: string | null;
    32→  gitStatusMap: Map<string, GitStatus>;
    33→  forceExpand?: boolean;
    34→  onSelect: (node: FileNode) => void;
    35→  onNewFile: (dirPath: string) => void;
    36→  onRename: (node: FileNode, newName: string) => void;
    37→  onDelete: (node: FileNode) => void;
    38→  onStartRename: (path: string) => void;
    39→  onCancelRename: () => void;
    40→}
    41→
    42→function FileItem({
    43→  node,
    44→  depth,
    45→  selectedPath,
    46→  renamingPath,
    47→  gitStatusMap,
    48→  forceExpand = false,
    49→  onSelect,
    50→  onNewFile,
    51→  onRename,
    52→  onDelete,
    53→  onStartRename,
    54→  onCancelRename,
    55→}: FileItemProps) {
    56→  const [expanded, setExpanded] = useState(true);
    57→  const isExpanded = forceExpand || expanded;
    58→  const isSelected = node.path === selectedPath;
    59→  const isRenaming = renamingPath === node.path;
    60→  const isMarkdown = node.extension === ".md" || node.extension === ".mdx";
