   203→const SIDEBAR_WIDTH_KEY = "ovid:sidebarWidth";
   204→const SIDEBAR_MIN = 180;
   205→const SIDEBAR_MAX = 480;
   206→const SIDEBAR_DEFAULT = 240;
   207→
   208→export function Sidebar({
   209→  tree,
   210→  selectedPath,
   211→  renamingPath,
   212→  visible,
   213→  workspaceName,
   214→  gitStatusMap,
   215→  onSelect,
   216→  onOpenWorkspace,
   217→  onOpenSwitcher,
   218→  onNewFile,
   219→  onRename,
   220→  onDelete,
   221→  onStartRename,
   222→  onCancelRename,
   223→}: SidebarProps) {
   224→  const [filterQuery, setFilterQuery] = useState("");
   225→  const [sidebarWidth, setSidebarWidth] = useState(() => {
   226→    const stored = localStorage.getItem(SIDEBAR_WIDTH_KEY);
   227→    const parsed = stored ? Number(stored) : SIDEBAR_DEFAULT;
   228→    if (!Number.isFinite(parsed)) return SIDEBAR_DEFAULT;
   229→    return Math.min(SIDEBAR_MAX, Math.max(SIDEBAR_MIN, parsed));
   230→  });
   231→  const [isResizing, setIsResizing] = useState(false);
   232→  const dragStartX = useRef(0);
   233→  const dragStartWidth = useRef(0);
   234→  const isMounted = useRef(true);
   235→  const activeDragListeners = useRef<{
   236→    onMouseMove: (ev: MouseEvent) => void;
   237→    onMouseUp: (ev: MouseEvent) => void;
   238→  } | null>(null);
   239→  useEffect(() => {
   240→    isMounted.current = true;
   241→    return () => {
   242→      const listeners = activeDragListeners.current;
   243→      if (listeners) {
   244→        window.removeEventListener("mousemove", listeners.onMouseMove);
   245→        window.removeEventListener("mouseup", listeners.onMouseUp);
   246→        activeDragListeners.current = null;
   247→      }
   248→      isMounted.current = false;
   249→    };
   250→  }, []);
   251→
   252→  function handleResizeMouseDown(e: React.MouseEvent) {
   253→    e.preventDefault();
   254→    setIsResizing(true);
   255→    dragStartX.current = e.clientX;
   256→    dragStartWidth.current = sidebarWidth;
   257→
   258→    const onMouseMove = (ev: MouseEvent) => {
   259→      if (!isMounted.current) return;
   260→      const delta = ev.clientX - dragStartX.current;
   261→      const next = Math.min(SIDEBAR_MAX, Math.max(SIDEBAR_MIN, dragStartWidth.current + delta));
   262→      setSidebarWidth(next);
   263→    };
   264→
   265→    const onMouseUp = (ev: MouseEvent) => {
   266→      window.removeEventListener("mousemove", onMouseMove);
   267→      window.removeEventListener("mouseup", onMouseUp);
   268→      activeDragListeners.current = null;
   269→      if (!isMounted.current) return;
   270→      const delta = ev.clientX - dragStartX.current;
   271→      const final = Math.min(SIDEBAR_MAX, Math.max(SIDEBAR_MIN, dragStartWidth.current + delta));
   272→      localStorage.setItem(SIDEBAR_WIDTH_KEY, String(final));
   273→      setIsResizing(false);
   274→    };
   275→
   276→    activeDragListeners.current = { onMouseMove, onMouseUp };
   277→    window.addEventListener("mousemove", onMouseMove);
   278→    window.addEventListener("mouseup", onMouseUp);
   279→  }
   280→
   281→  return (
   282→    <div
   283→      className={`sidebar ${visible ? "" : "hidden"}${isResizing ? " resizing" : ""}`}
   284→      style={visible ? { width: `${sidebarWidth}px`, minWidth: `${sidebarWidth}px` } : undefined}
   285→    >
   286→      <div className="sidebar-header">
   287→        <button
   288→          type="button"
   289→          className="sidebar-workspace-name"
   290→          onClick={onOpenSwitcher}
   291→          title="Switch workspace"
   292→        >
   293→          {workspaceName ?? "No workspace"}
   294→        </button>
   295→        <div className="sidebar-header-actions">
   296→          <button
   297→            type="button"
   298→            className="sidebar-open-btn"
   299→            onClick={onOpenWorkspace}
   300→            title="Open workspace"
   301→          >
   302→            ⊕
   303→          </button>
   304→        </div>
   305→      </div>
   306→
   307→      {tree.length > 0 && (
   308→        <div className="sidebar-filter">
   309→          <div className="relative flex-1">
   310→            <Input
   311→              type="text"
   312→              className="h-7 text-[12px] pr-6"
   313→              placeholder="Filter files…"
   314→              value={filterQuery}
   315→              onChange={(e) => setFilterQuery(e.target.value)}
   316→              onKeyDown={(e) => {
   317→                if (e.key === "Escape") setFilterQuery("");
   318→              }}
   319→            />
   320→            {filterQuery && (
   321→              <button
   322→                type="button"
   323→                className="absolute right-1.5 top-1/2 -translate-y-1/2 text-[9px] text-fg-subtle p-0.5 rounded leading-none hover:text-fg"
   324→                aria-label="Clear filter"
   325→                onClick={() => setFilterQuery("")}
   326→              >
   327→                ✕
   328→              </button>
   329→            )}
   330→          </div>
   331→        </div>
   332→      )}
   333→
   334→      <div className="sidebar-tree">
   335→        {tree.length === 0 ? (
   336→          <div className="sidebar-empty">
   337→            <p>No workspace open.</p>
   338→            <button type="button" className="sidebar-open-workspace-btn" onClick={onOpenWorkspace}>
   339→              Open folder
   340→            </button>
   341→          </div>
   342→        ) : (
   343→          sortNodes(filterQuery ? filterTree(tree, filterQuery) : tree).map((node, idx, sorted) => (
   344→            <Fragment key={node.path}>
   345→              {needsPageDivider(sorted, idx) && <div className="sidebar-section-divider" />}
   346→              <FileItem
   347→                node={node}
   348→                depth={0}
   349→                selectedPath={selectedPath}
   350→                renamingPath={renamingPath}
   351→                gitStatusMap={gitStatusMap}
   352→                forceExpand={filterQuery.length > 0}
   353→                onSelect={onSelect}
   354→                onNewFile={onNewFile}
   355→                onRename={onRename}
   356→                onDelete={onDelete}
   357→                onStartRename={onStartRename}
   358→                onCancelRename={onCancelRename}
   359→              />
   360→            </Fragment>
   361→          ))
   362→        )}
   363→      </div>
   364→
   365→      {/* biome-ignore lint/a11y/useSemanticElements: resize splitter widget requires div, not <hr> */}
   366→      <div
   367→        role="separator"
   368→        aria-label="Resize sidebar"
   369→        aria-valuenow={sidebarWidth}
   370→        aria-valuemin={SIDEBAR_MIN}
   371→        aria-valuemax={SIDEBAR_MAX}
   372→        tabIndex={0}
   373→        className="sidebar-resize-handle"
   374→        onMouseDown={handleResizeMouseDown}
   375→        onKeyDown={(e) => {
   376→          if (e.key !== "ArrowLeft" && e.key !== "ArrowRight") return;
   377→          e.preventDefault();
   378→          const step = e.shiftKey ? 24 : 12;
   379→          const delta = e.key === "ArrowRight" ? step : -step;
   380→          const next = Math.min(SIDEBAR_MAX, Math.max(SIDEBAR_MIN, sidebarWidth + delta));
   381→          setSidebarWidth(next);
   382→          localStorage.setItem(SIDEBAR_WIDTH_KEY, String(next));
   383→        }}
   384→      />
   385→    </div>
   386→  );
   387→}
