   101→fn walk_dir(path: &Path) -> Vec<FileNode> {
   102→    let Ok(entries) = std::fs::read_dir(path) else {
   103→        return Vec::new();
   104→    };
   105→
   106→    let mut entries: Vec<_> = entries.flatten().collect();
   107→    entries.sort_by_key(|e| e.file_name());
   108→
   109→    let mut nodes = Vec::new();
   110→
   111→    for entry in entries {
   112→        let entry_path = entry.path();
   113→        let name = entry.file_name().to_string_lossy().to_string();
   114→
   115→        if name.starts_with('.') {
   116→            continue;
   117→        }
   118→
   119→        if entry_path.is_dir() {
   120→            let children = walk_dir(&entry_path);
   121→            if !children.is_empty() {
   122→                nodes.push(FileNode {
   123→                    name,
   124→                    path: entry_path.to_string_lossy().to_string(),
   125→                    is_directory: true,
   126→                    children: Some(children),
   127→                    extension: None,
   128→                    title: None,
   129→                    draft: None,
   130→                    content_type: None,
   131→                });
   132→            }
   133→        } else {
   134→            let ext = entry_path
   135→                .extension()
   136→                .and_then(|e| e.to_str())
   137→                .unwrap_or("");
   138→            if ext == "md" || ext == "mdx" {
   139→                let (title, draft, content_type) = read_frontmatter_meta(&entry_path);
   140→                nodes.push(FileNode {
   141→                    name,
   142→                    path: entry_path.to_string_lossy().to_string(),
   143→                    is_directory: false,
   144→                    children: None,
   145→                    extension: Some(format!(".{}", ext)),
   146→                    title,
   147→                    draft,
   148→                    content_type,
   149→                });
   150→            }
   151→        }
   152→    }
   153→
   154→    nodes
   155→}
