   157→/// Canonicalize `requested` and verify it is inside `workspace_root`.
   158→fn validate_path(workspace_root: &Path, requested: &str) -> Result<PathBuf, String> {
   159→    let canonical_root =
   160→        std::fs::canonicalize(workspace_root).map_err(|e| format!("workspace root: {e}"))?;
   161→    let canonical_path =
   162→        std::fs::canonicalize(requested).map_err(|e| format!("invalid path: {e}"))?;
   163→    if !canonical_path.starts_with(&canonical_root) {
   164→        return Err("path is outside the opened workspace".to_string());
   165→    }
   166→    Ok(canonical_path)
   167→}
   168→
   169→/// Validate that a prospective new path's parent exists inside the workspace root.
   170→fn validate_new_path(workspace_root: &Path, requested: &str) -> Result<PathBuf, String> {
   171→    let canonical_root =
   172→        std::fs::canonicalize(workspace_root).map_err(|e| format!("workspace root: {e}"))?;
   173→    let new_path = PathBuf::from(requested);
   174→    let parent = new_path
   175→        .parent()
   176→        .ok_or("path has no parent directory")?;
   177→    let canonical_parent =
   178→        std::fs::canonicalize(parent).map_err(|e| format!("invalid parent path: {e}"))?;
   179→    if !canonical_parent.starts_with(&canonical_root) {
   180→        return Err("path is outside the opened workspace".to_string());
   181→    }
   182→    Ok(new_path)
   183→}
