   185→/// Write content atomically: write to a sibling temp file then rename over the target.
   186→fn write_atomic(path: &Path, content: &str) -> std::io::Result<()> {
   187→    let dir = path
   188→        .parent()
   189→        .ok_or_else(|| std::io::Error::new(std::io::ErrorKind::InvalidInput, "no parent dir"))?;
   190→    let tmp_name = format!(
   191→        ".~{}.tmp",
   192→        path.file_name().unwrap_or_default().to_string_lossy()
   193→    );
   194→    let tmp_path = dir.join(&tmp_name);
   195→
   196→    let mut file = std::fs::File::create(&tmp_path)?;
   197→    file.write_all(content.as_bytes())?;
   198→    file.flush()?;
   199→    file.sync_all()?;
   200→    drop(file);

