   211→fn derive_workspace_meta(root: &Path, is_amytis_workspace: bool) -> (PathBuf, Option<String>) {
   212→    let pub_dir = root.join("public");
   213→    let asset_root = if pub_dir.is_dir() { pub_dir } else { root.to_path_buf() };
   214→    let cdn_base = if is_amytis_workspace {
   215→        parse_cdn_base(&root.join("site.config.ts"))
