   222→#[tauri::command]
   223→async fn open_workspace_at_path(
   224→    path: String,
   225→    app: tauri::AppHandle,
   226→    state: State<'_, WorkspaceState>,
   227→) -> Result<Option<WorkspaceResult>, String> {
   228→    let root = PathBuf::from(&path);
   229→    if !root.is_dir() {
   230→        return Ok(None);
   231→    }
   232→
   233→    let name = root
   234→        .file_name()
   235→        .map(|n| n.to_string_lossy().to_string())
   236→        .unwrap_or_else(|| root.to_string_lossy().to_string());
   237→
   238→    let content_dir = root.join("content");
   239→    let tree_root = if content_dir.is_dir() { content_dir } else { root.clone() };
   240→
   241→    *state.tree_root.lock().map_err(|e| e.to_string())? = Some(tree_root.clone());
