   373→/// Search all markdown files under `path` for lines containing `query` (case-insensitive).
   374→fn search_dir(path: &Path, query: &str) -> Vec<SearchResult> {
   375→    let Ok(entries) = std::fs::read_dir(path) else {
   376→        return Vec::new();
   377→    };
   378→    let mut entries: Vec<_> = entries.flatten().collect();
   379→    entries.sort_by_key(|e| e.file_name());
   380→
   381→    let mut results = Vec::new();
   382→    for entry in entries {
   383→        let entry_path = entry.path();
   384→        let name = entry.file_name().to_string_lossy().to_string();
   385→        if name.starts_with('.') {
   386→            continue;
   387→        }
   388→        // Skip symlinks to prevent traversal outside the workspace
   389→        if entry.file_type().map(|ft| ft.is_symlink()).unwrap_or(false) {
   390→            continue;
   391→        }
   392→        if entry_path.is_dir() {
   393→            results.extend(search_dir(&entry_path, query));
   394→        } else {
   395→            let ext = entry_path.extension().and_then(|e| e.to_str()).unwrap_or("");
   396→            if ext != "md" && ext != "mdx" {
   397→                continue;
   398→            }
   399→            let Ok(content) = std::fs::read_to_string(&entry_path) else {
   400→                continue;
   401→            };
   402→            let q = query.to_lowercase();
   403→            let matches: Vec<SearchMatch> = content
   404→                .lines()
   405→                .enumerate()
   406→                .filter_map(|(i, line)| {
   407→                    if line.to_lowercase().contains(&q) {
   408→                        Some(SearchMatch {
   409→                            line_number: i + 1,
   410→                            line_content: line.trim().to_string(),
   411→                        })
   412→                    } else {
   413→                        None
   414→                    }
   415→                })
   416→                .collect();
   417→            if !matches.is_empty() {
   418→                let (title, _, _) = read_frontmatter_meta(&entry_path);
   419→                results.push(SearchResult {
   420→                    path: entry_path.to_string_lossy().to_string(),
   421→                    title,
   422→                    matches,
   423→                });
   424→            }
   425→        }
   426→    }
   427→    results
   428→}
   429→
   430→#[tauri::command]
   431→fn search_workspace(query: String, state: State<'_, WorkspaceState>) -> Result<Vec<SearchResult>, String> {
   432→    if query.trim().is_empty() {
   433→        return Ok(Vec::new());
   434→    }
   435→    // Clone root before releasing the lock so the mutex is not held during search
   436→    let root = {
   437→        let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   438→        root_guard.as_ref().ok_or("no workspace open")?.clone()
   439→    };
   440→    Ok(search_dir(&root, query.trim()))
   441→}
