    16→
    17→interface UseWorkspaceOptions {
    18→  showToast: (msg: string) => void;
    19→  flushPendingSave: () => Promise<void>;
    20→  handleCloseFile: () => Promise<void>;
    21→  handleSelectFile: (node: FileNode) => Promise<void>;
    22→  selectedFile: FileNode | null;
    23→  selectedPathRef: MutableRefObject<string | null>;
    24→  setSelectedFile: (node: FileNode | null) => void;
    25→  resetFileState: () => void;
    26→}
    27→
    28→function findNode(nodes: FileNode[], path: string): FileNode | undefined {
    29→  for (const n of nodes) {
    30→    if (n.path === path) return n;
    31→    if (n.children) {
    32→      const found = findNode(n.children, path);
    33→      if (found) return found;
    34→    }
    35→  }
    36→}
    37→
    38→export function useWorkspace({
    39→  showToast,
    40→  flushPendingSave,
    41→  handleCloseFile,
    42→  handleSelectFile,
    43→  selectedFile,
    44→  selectedPathRef,
    45→  setSelectedFile,
    46→  resetFileState,
    47→}: UseWorkspaceOptions) {
    48→  const [tree, setTree] = useState<FileNode[]>([]);
    49→  const [workspaceName, setWorkspaceName] = useState<string | null>(null);
    50→  const [workspaceRoot, setWorkspaceRoot] = useState<string | null>(null);
    51→  const [workspaceRootPath, setWorkspaceRootPath] = useState<string | null>(null);
    52→  const [isAmytisWorkspace, setIsAmytisWorkspace] = useState(false);
    53→  const [assetRoot, setAssetRoot] = useState<string | undefined>(undefined);
    54→  const [cdnBase, setCdnBase] = useState<string | undefined>(undefined);
    55→  const [renamingPath, setRenamingPath] = useState<string | null>(null);
    56→
    57→  const refreshTree = useCallback(async (): Promise<FileNode[]> => {
    58→    try {
    59→      const updated = await invoke<FileNode[]>("list_workspace");
    60→      setTree(updated);
    61→      return updated;
    62→    } catch (err) {
    63→      console.error("Failed to refresh tree:", err);
    64→      return [];
    65→    }
    66→  }, []);
    67→
    68→  const applyWorkspaceResult = useCallback(
    69→    (result: WorkspaceResult) => {
    70→      setTree(result.tree);
    71→      setWorkspaceName(result.name);
    72→      setWorkspaceRoot(result.treeRoot);
    73→      setWorkspaceRootPath(result.rootPath);
    74→      setIsAmytisWorkspace(result.isAmytisWorkspace);
    75→      setAssetRoot(result.assetRoot);
    76→      setCdnBase(result.cdnBase ?? undefined);
    77→      resetFileState();
    78→      if (!result.isAmytisWorkspace) {
    79→        showToast("This folder doesn't look like an Amytis workspace.");
    80→      }
    81→    },
    82→    [resetFileState, showToast]
    83→  );
    84→
    85→  const openWorkspaceAtPath = useCallback(
    86→    async (path: string) => {
    87→      await flushPendingSave();
    88→      try {
    89→        const result = await invoke<WorkspaceResult | null>("open_workspace_at_path", { path });
