    93→        console.error("Failed to open workspace:", err);
    94→        showToast(`Failed to open workspace: ${err}`);
    95→      }
    96→    },
    97→    [flushPendingSave, showToast, applyWorkspaceResult]
    98→  );
    99→
   100→  const handleOpenWorkspace = useCallback(async () => {
   101→    await flushPendingSave();
   102→    try {
   103→      const result = await invoke<WorkspaceResult | null>("open_workspace");
   104→      if (result) applyWorkspaceResult(result);
   105→    } catch (err) {
   106→      console.error("Failed to open workspace:", err);
   107→      showToast(`Failed to open workspace: ${err}`);
   108→    }
   109→  }, [flushPendingSave, showToast, applyWorkspaceResult]);
   110→
   111→  async function handleNewFile(dirPath: string, filename: string, contentType?: string) {
   112→    const slug = filename.replace(/\.md$/, "");
   113→    const filePath = `${dirPath}/${slug}.md`;
   114→    const content = contentType
   115→      ? createTypedFrontmatter(slug, contentType)
   116→      : createAmytisFrontmatter(slug);
   117→    try {
   118→      await invoke("create_file", { path: filePath, content });
   119→      const updated = await refreshTree();
   120→      const newNode = findNode(updated, filePath);
   121→      if (newNode) await handleSelectFile(newNode);
   122→    } catch (err) {
   123→      console.error("Failed to create file:", err);
   124→      showToast(`Failed to create file: ${err}`);
   125→    }
   126→  }
   127→
   128→  async function handleRename(node: FileNode, newName: string) {
   129→    setRenamingPath(null);
   130→    await flushPendingSave();
   131→    const dir = node.path.substring(0, node.path.lastIndexOf("/"));
   132→    const ext = node.extension ?? ".md";
   133→    const newPath = `${dir}/${newName}${newName.endsWith(ext) ? "" : ext}`;
   134→    try {
   135→      await invoke("rename_file", { oldPath: node.path, newPath });
   136→      const updated = await refreshTree();
   137→      if (selectedFile?.path === node.path) {
   138→        const renamed = findNode(updated, newPath);
   139→        if (renamed) {
   140→          selectedPathRef.current = newPath;
   141→          setSelectedFile(renamed);
   142→        }
   143→      }
   144→    } catch (err) {
   145→      console.error("Failed to rename file:", err);
   146→      showToast(`Failed to rename: ${err}`);
   147→    }
   148→  }
   149→
   150→  async function handleDelete(node: FileNode) {
   151→    const confirmed = window.confirm(`Move "${node.name}" to Trash?`);
   152→    if (!confirmed) return;
   153→    if (selectedFile?.path === node.path) {
   154→      await flushPendingSave();
   155→    }
   156→    try {
   157→      await invoke("trash_file", { path: node.path });
   158→      if (selectedFile?.path === node.path) await handleCloseFile();
