   167→    tree,
   168→    workspaceName,
   169→    workspaceRoot,
   170→    workspaceRootPath,
   171→    isAmytisWorkspace,
   172→    assetRoot,
   173→    cdnBase,
   174→    renamingPath,
   175→    setRenamingPath,
   176→    handleOpenWorkspace,
   177→    openWorkspaceAtPath,
   178→    handleNewFile,
   179→    handleRename,
   180→    handleDelete,
   181→  };
   182→}
