   513→/// Best-effort scanner: find `contentTypes` in `site.config.ts` and extract
   514→/// the top-level key names (post, page, note, …). Returns empty vec on any
   515→/// parse failure so callers gracefully degrade to the default frontmatter.
   516→fn parse_content_types(config_path: &Path) -> Vec<ContentType> {
   517→    use std::io::{BufRead, BufReader};
   518→    let Ok(file) = std::fs::File::open(config_path) else {
   519→        return Vec::new();
   520→    };
   521→    let mut reader = BufReader::new(file);
   522→    let mut type_names: Vec<ContentType> = Vec::new();
   523→    let mut depth: i32 = 0;
   524→    let mut found_content_types = false;
   525→    let mut content_types_depth: Option<i32> = None;
   526→    let mut line = String::new();
   527→
   528→    loop {
   529→        line.clear();
   530→        if reader.read_line(&mut line).unwrap_or(0) == 0 {
   531→            break;
   532→        }
   533→        let trimmed = line.trim();
   534→        let open_count = line.chars().filter(|&c| c == '{').count() as i32;
   535→        let close_count = line.chars().filter(|&c| c == '}').count() as i32;
   536→
   537→        match content_types_depth {
   538→            None if !found_content_types => {
   539→                if trimmed.contains("contentTypes") {
   540→                    found_content_types = true;
   541→                    depth += open_count - close_count;
   542→                    if open_count > 0 {
   543→                        content_types_depth = Some(depth);
   544→                    }
   545→                } else {
   546→                    depth += open_count - close_count;
   547→                }
   548→            }
   549→            None => {
   550→                // found keyword, waiting for opening brace
   551→                depth += open_count - close_count;
   552→                if open_count > 0 {
   553→                    content_types_depth = Some(depth);
   554→                }
   555→            }
   556→            Some(ct_depth) => {
   557→                let prev_depth = depth;
   558→                depth += open_count - close_count;
   559→                if depth < ct_depth {
   560→                    break;
   561→                }
   562→                if prev_depth == ct_depth {
   563→                    if let Some(name) = extract_ts_key(trimmed) {
   564→                        type_names.push(ContentType { name });
   565→                    }
   566→                }
   567→            }
   568→        }
   569→    }
   570→    type_names
   571→}
   572→
   573→fn extract_ts_key(line: &str) -> Option<String> {
   574→    let line = line.trim();
   575→    if line.starts_with("//") || line.starts_with('*') || line.starts_with("/*") {
   576→        return None;
   577→    }
   578→    let end = line.find(':')?;
   579→    let key = line[..end].trim().trim_matches('"').trim_matches('\'');
   580→    if !key.is_empty() && key.chars().all(|c| c.is_alphanumeric() || c == '_') {
   581→        Some(key.to_string())
   582→    } else {
   583→        None
   584→    }
   585→}
