   587→#[tauri::command]
   588→fn get_content_types(state: State<'_, WorkspaceState>) -> Result<Vec<ContentType>, String> {
   589→    let root_guard = state.workspace_root.lock().map_err(|e| e.to_string())?;
   590→    let root = match root_guard.as_ref() {
   591→        Some(r) => r.clone(),
   592→        None => return Ok(Vec::new()),
   593→    };
   594→    drop(root_guard);
   595→    let config = root.join("site.config.ts");
   596→    if !config.is_file() {
   597→        return Ok(Vec::new());
   598→    }
   599→    Ok(parse_content_types(&config))
