   610→
   611→/// Run a git subcommand rooted at `root`. Returns stdout on success or an
   612→/// error string (stderr) on failure. Returns an empty string if git is not
   613→/// found, so callers can treat a missing git as a graceful no-op.
   614→fn run_git(root: &str, args: &[&str]) -> Result<String, String> {
   615→    let mut cmd_args = vec!["-C", root];
   616→    cmd_args.extend_from_slice(args);
   617→    let output = std::process::Command::new("git")
   618→        .args(&cmd_args)
   619→        .output()
   620→        .map_err(|_| "git not found".to_string())?;
   621→    if !output.status.success() {
   622→        let stderr = String::from_utf8_lossy(&output.stderr).trim().to_string();
   623→        return Err(if stderr.is_empty() { "git command failed".to_string() } else { stderr });
   624→    }
   625→    Ok(String::from_utf8_lossy(&output.stdout).to_string())
   626→}
