   628→#[tauri::command]
   629→fn get_git_status(state: State<'_, WorkspaceState>) -> Result<Vec<GitFileStatus>, String> {
   630→    let root_guard = state.tree_root.lock().map_err(|e| e.to_string())?;
   631→    let root = match root_guard.as_ref() {
   632→        Some(r) => r.clone(),
   633→        None => return Ok(Vec::new()),
   634→    };
   635→    drop(root_guard);
   636→    let root_str = root.to_string_lossy().to_string();
   637→
   638→    // Find the git repo root (may differ from tree_root if content/ is a subdir)
   639→    let git_root = match run_git(&root_str, &["rev-parse", "--show-toplevel"]) {
   640→        Ok(s) => s.trim().to_string(),
   641→        Err(_) => return Ok(Vec::new()), // not a git repo or git not found
   642→    };
   643→
   644→    let porcelain = match run_git(&git_root, &["status", "--porcelain"]) {
   645→        Ok(s) => s,
   646→        Err(_) => return Ok(Vec::new()),
   647→    };
   648→
   649→    let mut statuses = Vec::new();
   650→    for line in porcelain.lines() {
   651→        if line.len() < 4 {
   652→            continue;
   653→        }
   654→        let xy = &line[..2];
   655→        let path_part = line[3..].trim();
   656→        // Handle renames: "R old -> new" — take the destination
   657→        let file_path = if path_part.contains(" -> ") {
   658→            path_part.split(" -> ").nth(1).unwrap_or(path_part)
   659→        } else {
   660→            path_part
   661→        };
   662→        let abs_path = PathBuf::from(&git_root).join(file_path).to_string_lossy().into_owned();
   663→        let status = if xy.starts_with('?') {
   664→            "untracked"
   665→        } else if xy.chars().next().map(|c| c != ' ').unwrap_or(false) {
   666→            "staged"
   667→        } else {
   668→            "modified"
   669→        };
   670→        statuses.push(GitFileStatus { path: abs_path, status: status.to_string() });
   671→    }
   672→    Ok(statuses)
   673→}
