     1→import type { FileNode, GitStatus } from "./types";
     2→
     3→export const GIT_PRIORITY: GitStatus[] = ["staged", "modified", "untracked"];
     4→
     5→export function rollupGitStatus(
     6→  node: FileNode,
     7→  map: Map<string, GitStatus>
     8→): GitStatus | undefined {
     9→  if (!node.isDirectory) return map.get(node.path);
    10→  let best: GitStatus | undefined;
    11→  for (const child of node.children ?? []) {
    12→    const childStatus = rollupGitStatus(child, map);
    13→    if (!childStatus) continue;
    14→    if (!best || GIT_PRIORITY.indexOf(childStatus) < GIT_PRIORITY.indexOf(best)) {
    15→      best = childStatus;
    16→    }
    17→  }
    18→  return best;
    19→}
    20→
    21→export function filterTree(nodes: FileNode[], query: string): FileNode[] {
    22→  const q = query.toLowerCase();
    23→  return nodes.flatMap((node) => {
    24→    if (node.isDirectory) {
    25→      const filtered = filterTree(node.children ?? [], q);
    26→      return filtered.length > 0 ? [{ ...node, children: filtered }] : [];
    27→    }
    28→    const matches =
    29→      node.name.toLowerCase().includes(q) || node.title?.toLowerCase().includes(q) === true;
    30→    return matches ? [node] : [];
    31→  });
    32→}
    33→
    34→// ---------------------------------------------------------------------------
    35→// Content-type ordering
    36→// ---------------------------------------------------------------------------
    37→
    38→const CONTENT_TYPE_RANK: Record<string, number> = {
    39→  flow: 0,
    40→  note: 1,
    41→  post: 2,
    42→  series: 3,
    43→  book: 4,
    44→  // unknown types (no contentType) get rank 5
    45→  page: 6,
    46→};
    47→
    48→function nodeRank(node: FileNode): number {
    49→  if (node.isDirectory) return -1; // directories always first
    50→  return CONTENT_TYPE_RANK[node.contentType ?? ""] ?? 5;
    51→}
    52→
    53→/** Sort nodes: directories first (alphabetical), then files by content-type
    54→ *  priority (flow → note → post → series → book → unknown → page),
    55→ *  alphabetical within each group. */
    56→export function sortNodes(nodes: FileNode[]): FileNode[] {
    57→  return [...nodes].sort((a, b) => {
    58→    const diff = nodeRank(a) - nodeRank(b);
    59→    if (diff !== 0) return diff;
    60→    return a.name.localeCompare(b.name);
    61→  });
    62→}
    63→
    64→/** Returns true when a divider should be rendered before `nodes[index]`:
    65→ *  the node is the first `page`-type file and there are non-page files
    66→ *  earlier in the same list. */
    67→export function needsPageDivider(nodes: FileNode[], index: number): boolean {
    68→  const node = nodes[index];
    69→  if (node.isDirectory || node.contentType !== "page") return false;
    70→  if (index > 0 && nodes[index - 1].contentType === "page") return false;
    71→  return nodes.slice(0, index).some((n) => !n.isDirectory && n.contentType !== "page");
    72→}
