   115→
   116→  // Auto-reopen last workspace on launch (once)
   117→  const autoReopenAttempted = useRef(false);
   118→  useEffect(() => {
   119→    if (
   120→      autoReopenAttempted.current ||
   121→      workspaceRootPath !== null ||
   122→      recentWorkspaces.length === 0 ||
   123→      localStorage.getItem(AUTO_REOPEN_KEY) === "true"
   124→    )
   125→      return;
   126→    autoReopenAttempted.current = true;
   127→    void openWorkspaceAtPath(recentWorkspaces[0].rootPath);
   128→  }, [recentWorkspaces, openWorkspaceAtPath, workspaceRootPath]);
   129→
   130→  // Reset per-file UI state when switching files (selectedFile is the trigger, not used in body)
   131→  // biome-ignore lint/correctness/useExhaustiveDependencies: selectedFile is the intended trigger
   132→  useEffect(() => {
   133→    setSessionBaseline(null);
   134→    setBaselineCaptured(false);
   135→    setCoverImageVisible(false);
   136→  }, [selectedFile]);
   137→
   138→  // Capture baseline on first word-count event for the new file (including empty files)
   139→  useEffect(() => {
   140→    if (!baselineCaptured) {
   141→      setSessionBaseline(wordCount);
   142→      setBaselineCaptured(true);
   143→    }
   144→  }, [wordCount, baselineCaptured]);
   145→
   146→  // Global keyboard shortcuts
   147→  useEffect(() => {
   148→    function onKeyDown(e: KeyboardEvent) {
   149→      // Escape exits zen mode (before other guards)
   150→      if (
   151→        e.key === "Escape" &&
   152→        zenMode &&
   153→        !modal &&
   154→        !commitDialog &&
   155→        !switcherOpen &&
   156→        !workspaceSwitcherOpen
   157→      ) {
   158→        setZenMode(false);
   159→        return;
   160→      }
   161→      if (!e.metaKey && !e.ctrlKey) return;
   162→      // Ctrl+Cmd+Z — zen mode (macOS); avoids conflict with Redo (Cmd+Shift+Z)
   163→      if (e.metaKey && e.ctrlKey && e.key === "z") {
   164→        e.preventDefault();
   165→        setZenMode((v) => !v);
   166→        return;
   167→      }
   168→      // Mode toggles work even when editor has focus
   169→      if (e.shiftKey && e.key === "P") {
