      )
        return;
      switch (e.key) {
        case "\\":
          e.preventDefault();
          setSidebarVisible((v) => {
            const next = !v;
            localStorage.setItem(SIDEBAR_VISIBLE_KEY, String(next));
            return next;
          });
          break;
        case "o":
          e.preventDefault();
          if (e.shiftKey) {
            setWorkspaceSwitcherOpen(true);
          } else {
            void handleOpenWorkspace();
          }
          break;
        case "F":
          if (e.shiftKey) {
            e.preventDefault();
            if (workspaceRoot) setSearchOpen((v) => !v);
          }
          break;
        case "G":
          if (e.shiftKey && isGitRepo) {
            e.preventDefault();
            void getBranch()
              .then((branch) => {
                const title = parsedFrontmatter.title ?? selectedFile?.name ?? "";
                setCommitDialog({ message: `Update: ${title}`, branch });
              })
              .catch(() => showToast("Failed to get git branch"));
          }
          break;
        case "p":
          e.preventDefault();
          if (tree.length > 0) setSwitcherOpen(true);
          break;
        case "n":
          e.preventDefault();
          if (workspaceRoot)
            setModal({ type: "new-file", dirPath: workspaceRoot, contentType: "post" });
          break;
        case "T":
          if (e.shiftKey) {
            e.preventDefault();
            if (workspaceRoot) void handleNewTodayFlow();
          }
          break;
        case "s":
          e.preventDefault();
          void flushPendingSave();
          break;
        case "w":
          e.preventDefault();
          void handleCloseFile();
          break;
      }
    }
    window.addEventListener("keydown", onKeyDown);
    return () => window.removeEventListener("keydown", onKeyDown);
  }, [
    flushPendingSave,
    handleCloseFile,
    handleOpenWorkspace,
    handleNewTodayFlow,
    workspaceRoot,
    tree,
    isGitRepo,
    getBranch,
    parsedFrontmatter,
    selectedFile,
    showToast,
    zenMode,
    modal,
    commitDialog,
    switcherOpen,
    workspaceSwitcherOpen,
  ]);

  // Refresh git status after each save completes
